import type { HealthMetric } from '@shared/schema';
import { format, subDays } from 'date-fns';

interface MetricsChartProps {
  data: HealthMetric[];
  metricType: string;
  unit: string;
  timeRange: string;
}

export function MetricsChart({ data, metricType, unit, timeRange }: MetricsChartProps) {
  const chartData = useMemo(() => {
    // Filter data based on time range
    let filteredData = [...data];
    const now = new Date();

    if (timeRange === '7d') {
      const cutoff = subDays(now, 7);
      filteredData = data.filter(d => new Date(d.recordedAt) >= cutoff);
    } else if (timeRange === '30d') {
      const cutoff = subDays(now, 30);
      filteredData = data.filter(d => new Date(d.recordedAt) >= cutoff);
    } else if (timeRange === '90d') {
      const cutoff = subDays(now, 90);
      filteredData = data.filter(d => new Date(d.recordedAt) >= cutoff);
    }

    // Sort by date
    filteredData.sort((a, b) => new Date(a.recordedAt).getTime() - new Date(b.recordedAt).getTime());

    // Transform data for chart
    return filteredData.map(item => {
      const date = format(new Date(item.recordedAt), 'MMM dd');

      if (metricType === 'bloodPressure') {
        return {
          date,
          systolic: item.bloodPressureSystolic,
          diastolic: item.bloodPressureDiastolic,
        };
      }

      let value: number | null = null;
      switch (metricType) {
        case 'bloodSugar':
          value = item.bloodSugar ? parseFloat(item.bloodSugar) : null;
          break;
        case 'heartRate':
          value = item.heartRate;
          break;
        case 'weight':
          value = item.weight ? parseFloat(item.weight) : null;
          break;
        case 'steps':
          value = item.steps;
          break;
      }

      return {
        date,
        value,
      };
    }).filter(item => metricType === 'bloodPressure' ? (item.systolic !== null || item.diastolic !== null) : item.value !== null);
  }, [data, metricType, timeRange]);

  if (chartData.length === 0) {
    return (
      <div className="flex h-[300px] items-center justify-center text-gray-500">
        No data available for the selected time range
      </div>
    );
  }

  if (metricType === 'bloodPressure') {
    return (
      <ResponsiveContainer width="100%" height={300}>
        <LineChart data={chartData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis 
            dataKey="date" 
            tick={{ fontSize: 12 }}
            angle={-45}
            textAnchor="end"
            height={60}
          />
          <YAxis tick={{ fontSize: 12 }} />
          <Tooltip />
          <Legend />
          <Line 
            type="monotone" 
            dataKey="systolic" 
            stroke="#ef4444" 
            strokeWidth={2}
            name="Systolic"
            dot={{ r: 4 }}
          />
          <Line 
            type="monotone" 
            dataKey="diastolic" 
            stroke="#3b82f6" 
            strokeWidth={2}
            name="Diastolic"
            dot={{ r: 4 }}
          />
        </LineChart>
      </ResponsiveContainer>
    );
  }

  const getLineColor = () => {
    switch (metricType) {
      case 'bloodSugar':
        return '#3b82f6';
      case 'heartRate':
        return '#ec4899';
      case 'weight':
        return '#10b981';
      case 'steps':
        return '#8b5cf6';
      default:
        return '#6366f1';
    }
  };

  return (
    <ResponsiveContainer width="100%" height={300}>
      <LineChart data={chartData}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis 
          dataKey="date" 
          tick={{ fontSize: 12 }}
          angle={-45}
          textAnchor="end"
          height={60}
        />
        <YAxis 
          tick={{ fontSize: 12 }}
          label={{ value: unit, angle: -90, position: 'insideLeft' }}
        />
        <Tooltip />
        <Line 
          type="monotone" 
          dataKey="value" 
          stroke={getLineColor()} 
          strokeWidth={2}
          dot={{ r: 4 }}
          name={unit}
        />
      </LineChart>
    </ResponsiveContainer>
  );
}

client/src/hooks/mutations/useSignup.ts.content:
import { useMutation } from '@tanstack/react-query';
import { authService } from '@/services/authService';
import type { SignupRequest, AuthResponse } from '@/types/auth.types';
import { useToast } from '@/hooks/use-toast';
import { useAuthStore } from '@/stores/authStore';
import { useLocation } from 'wouter';
import { ROUTES } from '@/config/routes';

export const useSignup = () => {
  const { toast } = useToast();
  const setUser = useAuthStore((state: ReturnType<typeof useAuthStore.getState>) => state.setUser);
  const [, navigate] = useLocation();

  return useMutation<AuthResponse, Error, SignupRequest>({
    mutationFn: authService.signup,
    onSuccess: (data) => {
      setUser(data.user);
      toast({
        title: 'Success!',
        description: 'Your account has been created successfully.',
        variant: 'default',
      });
      navigate(ROUTES.LOGIN);
    },
    onError: (error) => {
      toast({
        title: 'Signup Failed',
        description: error.message || 'Something went wrong. Please try again.',
        variant: 'destructive',
      });
    },
  });
};

client/src/components/ui/alert.tsx.content:
import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const alertVariants = cva(
  "relative w-full rounded-lg border p-4 [&>svg~*]:pl-7 [&>svg+div]:translate-y-[-3px] [&>svg]:absolute [&>svg]:left-4 [&>svg]:top-4 [&>svg]:text-foreground",
  {
    variants: {
      variant: {
        default: "bg-background text-foreground",
        destructive:
          "border-destructive/50 text-destructive dark:border-destructive [&>svg]:text-destructive",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

const Alert = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & VariantProps<typeof alertVariants>
>(({ className, variant, ...props }, ref) => (
  <div
    ref={ref}
    role="alert"
    className={cn(alertVariants({ variant }), className)}
    {...props}
  />
))
Alert.displayName = "Alert"

const AlertTitle = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLHeadingElement>
>(({ className, ...props }, ref) => (
  <h5
    ref={ref}
    className={cn("mb-1 font-medium leading-none tracking-tight", className)}
    {...props}
  />
))
AlertTitle.displayName = "AlertTitle"

const AlertDescription = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLParagraphElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("text-sm [&_p]:leading-relaxed", className)}
    {...props}
  />
))
AlertDescription.displayName = "AlertDescription"

export { Alert, AlertTitle, AlertDescription }

