import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useLocation } from 'wouter';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { profileDataSchema, type ProfileDataFormValues } from '@/schemas/profileData';
import {
  genderOptions,
  diabetesTypeOptions,
  dayOptions,
  monthOptions,
  yearOptions,
  weightOptions,
  heightOptions,
} from '@/mocks/profileData';
import { ROUTES } from '@/config/routes';
import { useToast } from '@/hooks/use-toast';

export function ProfileData() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const form = useForm<ProfileDataFormValues>({
    resolver: zodResolver(profileDataSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      gender: undefined,
      birthDay: '',
      birthMonth: '',
      birthYear: '',
      diagnosisDay: '',
      diagnosisMonth: '',
      diagnosisYear: '',
      weight: '',
      height: '',
      diabetesType: undefined,
    },
  });

  const onSubmit = (data: ProfileDataFormValues) => {
    console.log('Profile data submitted:', data);
    toast({
      title: 'Profile Updated',
      description: 'Your profile information has been saved successfully.',
    });
    setLocation(ROUTES.DASHBOARD);
  };

  return (
    <div className="flex min-h-screen" style={{ background: '#F7F9F9' }}>
      {/* Left Sidebar - Hidden on mobile, visible on large screens */}
      <div
        className="hidden lg:flex w-[309px] items-center justify-center px-8"
        style={{ background: '#00856F' }}
      >
        <h1
          className="text-white font-bold leading-[130%] tracking-[-0.01em] text-3xl lg:text-[48px]"
          style={{
            fontFamily: "'Open Sauce Sans', sans-serif",
          }}
          data-testid="text-sidebar-heading"
        >
          Help our App understand you!
        </h1>
      </div>

      {/* Main Content */}
      <main className="flex-1 px-4 sm:px-8 lg:px-16 py-8 lg:py-12">
        <div className="max-w-[762px] mx-auto">
          {/* Page Title */}
          <h1
            className="font-bold leading-[130%] tracking-[-0.01em] mb-8 lg:mb-12 text-3xl sm:text-4xl lg:text-[48px]"
            style={{
              fontFamily: "'Open Sauce Sans', sans-serif",
              color: '#00856F',
            }}
            data-testid="text-page-heading"
          >
            Tell Us about Yourself
          </h1>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8 lg:space-y-12">
              {/* Personal Details Section */}
              <div>
                <h2
                  className="font-bold leading-[130%] tracking-[-0.01em] mb-6 lg:mb-8 text-2xl sm:text-3xl lg:text-[32px]"
                  style={{
                    fontFamily: "'Open Sauce Sans', sans-serif",
                    color: '#00856F',
                  }}
                  data-testid="text-personal-details"
                >
                  Personal Details
                </h2>

                <div className="space-y-6">
                  {/* First Name and Last Name Row */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <FormField
                      control={form.control}
                      name="firstName"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel
                            className="text-[20px] font-normal"
                            style={{ fontFamily: "'Inter', sans-serif" }}
                          >
                            First Name
                          </FormLabel>
                          <FormControl>
                            <Input
                              placeholder="First Name"
                              {...field}
                              className="h-[56px] rounded-[10px] border-[#D8DADC] text-[16px]"
                              style={{ fontFamily: "'Inter', sans-serif" }}
                              data-testid="input-first-name"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="lastName"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel
                            className="text-[20px] font-normal"
                            style={{ fontFamily: "'Inter', sans-serif" }}
                          >
                            Last Name
                          </FormLabel>
                          <FormControl>
                            <Input
                              placeholder="Last Name"
                              {...field}
                              className="h-[56px] rounded-[10px] border-[#D8DADC] text-[16px]"
                              style={{ fontFamily: "'Inter', sans-serif" }}
                              data-testid="input-last-name"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  {/* Gender and Date of Birth Row */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <FormField
                      control={form.control}
                      name="gender"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel
                            className="text-[20px] font-normal"
                            style={{ fontFamily: "'Inter', sans-serif" }}
                          >
                            Gender
                          </FormLabel>
                          <Select onValueChange={field.onChange} value={field.value}>
                            <FormControl>
                              <SelectTrigger
                                className="h-[56px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                style={{ fontFamily: "'Inter', sans-serif" }}
                                data-testid="select-gender"
                              >
                                <SelectValue placeholder="Male/Female" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {genderOptions.map((option) => (
                                <SelectItem
                                  key={option.value}
                                  value={option.value}
                                  data-testid={`option-gender-${option.value}`}
                                >
                                  {option.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <div>
                      <FormLabel
                        className="text-[20px] font-normal block mb-2"
                        style={{ fontFamily: "'Inter', sans-serif" }}
                      >
                        Date of Birth
                      </FormLabel>
                      <div className="grid grid-cols-3 gap-3">
                        <FormField
                          control={form.control}
                          name="birthDay"
                          render={({ field }) => (
                            <FormItem>
                              <Select onValueChange={field.onChange} value={field.value}>
                                <FormControl>
                                  <SelectTrigger
                                    className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                    style={{ fontFamily: "'Inter', sans-serif" }}
                                    data-testid="select-birth-day"
                                  >
                                    <SelectValue placeholder="DD" />
                                  </SelectTrigger>
                                </FormControl>
                                <SelectContent>
                                  {dayOptions.map((option) => (
                                    <SelectItem
                                      key={option.value}
                                      value={option.value}
                                      data-testid={`option-birth-day-${option.value}`}
                                    >
                                      {option.label}
                                    </SelectItem>
                                  ))}
                                </SelectContent>
                              </Select>
                              <FormMessage />
                            </FormItem>
                          )}
                        />

                        <FormField
                          control={form.control}
                          name="birthMonth"
                          render={({ field }) => (
                            <FormItem>
                              <Select onValueChange={field.onChange} value={field.value}>
                                <FormControl>
                                  <SelectTrigger
                                    className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                    style={{ fontFamily: "'Inter', sans-serif" }}
                                    data-testid="select-birth-month"
                                  >
                                    <SelectValue placeholder="MM" />
                                  </SelectTrigger>
                                </FormControl>
                                <SelectContent>
                                  {monthOptions.map((option) => (
                                    <SelectItem
                                      key={option.value}
                                      value={option.value}
                                      data-testid={`option-birth-month-${option.value}`}
                                    >
                                      {option.label}
                                    </SelectItem>
                                  ))}
                                </SelectContent>
                              </Select>
                              <FormMessage />
                            </FormItem>
                          )}
                        />

                        <FormField
                          control={form.control}
                          name="birthYear"
                          render={({ field }) => (
                            <FormItem>
                              <Select onValueChange={field.onChange} value={field.value}>
                                <FormControl>
                                  <SelectTrigger
                                    className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                    style={{ fontFamily: "'Inter', sans-serif" }}
                                    data-testid="select-birth-year"
                                  >
                                    <SelectValue placeholder="YYYY" />
                                  </SelectTrigger>
                                </FormControl>
                                <SelectContent>
                                  {yearOptions.map((option) => (
                                    <SelectItem
                                      key={option.value}
                                      value={option.value}
                                      data-testid={`option-birth-year-${option.value}`}
                                    >
                                      {option.label}
                                    </SelectItem>
                                  ))}
                                </SelectContent>
                              </Select>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Diagnosis Section */}
              <div>
                <h2
                  className="font-bold leading-[130%] tracking-[-0.01em] mb-6 lg:mb-8 text-2xl sm:text-3xl lg:text-[32px]"
                  style={{
                    fontFamily: "'Open Sauce Sans', sans-serif",
                    color: '#00856F',
                  }}
                  data-testid="text-diagnosis"
                >
                  Diagnosis
                </h2>

                <div className="space-y-6">
                  {/* Diagnosis Date Row */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <div>
                      <FormLabel
                        className="text-[20px] font-normal block mb-2"
                        style={{ fontFamily: "'Inter', sans-serif" }}
                      >
                        Diagnosis Date
                      </FormLabel>
                      <div className="grid grid-cols-3 gap-3">
                        <FormField
                          control={form.control}
                          name="diagnosisDay"
                          render={({ field }) => (
                            <FormItem>
                              <Select onValueChange={field.onChange} value={field.value}>
                                <FormControl>
                                  <SelectTrigger
                                    className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                    style={{ fontFamily: "'Inter', sans-serif" }}
                                    data-testid="select-diagnosis-day"
                                  >
                                    <SelectValue placeholder="DD" />
                                  </SelectTrigger>
                                </FormControl>
                                <SelectContent>
                                  {dayOptions.map((option) => (
                                    <SelectItem
                                      key={option.value}
                                      value={option.value}
                                      data-testid={`option-diagnosis-day-${option.value}`}
                                    >
                                      {option.label}
                                    </SelectItem>
                                  ))}
                                </SelectContent>
                              </Select>
                              <FormMessage />
                            </FormItem>
                          )}
                        />

                        <FormField
                          control={form.control}
                          name="diagnosisMonth"
                          render={({ field }) => (
                            <FormItem>
                              <Select onValueChange={field.onChange} value={field.value}>
                                <FormControl>
                                  <SelectTrigger
                                    className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                    style={{ fontFamily: "'Inter', sans-serif" }}
                                    data-testid="select-diagnosis-month"
