                                  </SelectTrigger>
                                </FormControl>
                                <SelectContent>
                                  {yearOptions.map((option) => (
                                    <SelectItem
                                      key={option.value}
                                      value={option.value}
                                      data-testid={`option-diagnosis-year-${option.value}`}
                                    >
                                      {option.label}
                                    </SelectItem>
                                  ))}
                                </SelectContent>
                              </Select>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>
                    </div>

                    {/* Weight and Height */}
                    <div className="grid grid-cols-2 gap-3">
                      <FormField
                        control={form.control}
                        name="weight"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel
                              className="text-[20px] font-normal"
                              style={{ fontFamily: "'Inter', sans-serif" }}
                            >
                              Weight(kg)
                            </FormLabel>
                            <Select onValueChange={field.onChange} value={field.value}>
                              <FormControl>
                                <SelectTrigger
                                  className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                  style={{ fontFamily: "'Inter', sans-serif" }}
                                  data-testid="select-weight"
                                >
                                  <SelectValue placeholder="0" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                {weightOptions.map((option) => (
                                  <SelectItem
                                    key={option.value}
                                    value={option.value}
                                    data-testid={`option-weight-${option.value}`}
                                  >
                                    {option.label}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="height"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel
                              className="text-[20px] font-normal"
                              style={{ fontFamily: "'Inter', sans-serif" }}
                            >
                              Height(cm)
                            </FormLabel>
                            <Select onValueChange={field.onChange} value={field.value}>
                              <FormControl>
                                <SelectTrigger
                                  className="h-[46px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                  style={{ fontFamily: "'Inter', sans-serif" }}
                                  data-testid="select-height"
                                >
                                  <SelectValue placeholder="0" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                {heightOptions.map((option) => (
                                  <SelectItem
                                    key={option.value}
                                    value={option.value}
                                    data-testid={`option-height-${option.value}`}
                                  >
                                    {option.label}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>
                  </div>

                  {/* Type of Diabetes */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <FormField
                      control={form.control}
                      name="diabetesType"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel
                            className="text-[20px] font-normal"
                            style={{ fontFamily: "'Inter', sans-serif" }}
                          >
                            Type of Diabetes
                          </FormLabel>
                          <Select onValueChange={field.onChange} value={field.value}>
                            <FormControl>
                              <SelectTrigger
                                className="h-[56px] rounded-[10px] border-[#D8DADC] text-[16px]"
                                style={{ fontFamily: "'Inter', sans-serif" }}
                                data-testid="select-diabetes-type"
                              >
                                <SelectValue placeholder="Type 1 Diabetes" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {diabetesTypeOptions.map((option) => (
                                <SelectItem
                                  key={option.value}
                                  value={option.value}
                                  data-testid={`option-diabetes-${option.value}`}
                                >
                                  {option.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                </div>
              </div>

              {/* Submit Button */}
              <Button
                type="submit"
                className="w-full h-[56px] rounded-[10px] text-white text-[18px] font-semibold"
                style={{
                  background: '#00856F',
                  fontFamily: "'Inter', sans-serif",
                }}
                data-testid="button-submit-details"
              >
                Submit Details
              </Button>
            </form>
          </Form>
        </div>
      </main>
    </div>
  );
}

